sql_query:
SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Cancer type" = 'Renal cell' AND "Type of combination" = 'ICI+Anti-VEGF';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Treatment regimen" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Renal cell' AND "Type of combination" = 'ICI+Anti-VEGF'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_anti_vegf_agents(source_value) AS "anti_vegf_agents"
FROM base;
